# Find a prime factor
def find_factor(n):
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            print(f"{n} is divisible by {i}")
            break
    else:
        # loop ran to completion without break → no factor found
        print(f"{n} is prime")

