import re
from collections import defaultdict

def parse_log_file(filepath, max_lines=None):
    """
    Parse a log file and return a summary of error events by category.
    Skips comments and blank lines. Stops at max_lines if specified.
    """
    error_pattern = re.compile(
        r"^(?P<timestamp>\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2}) "
        r"\[(?P<level>ERROR|WARN|INFO)\] "
        r"(?P<category>\w+): (?P<message>.+)$"
    )

    errors_by_category = defaultdict(list)
    line_count = 0

    with open(filepath) as f:
        for line in f:
            # Early termination: honour max_lines limit
            if max_lines is not None and line_count >= max_lines:
                break

            line_count += 1
            stripped = line.strip()

            # Skip blanks and comments
            if not stripped or stripped.startswith("#"):
                continue

            match = error_pattern.match(stripped)
            if not match:
                continue    # skip malformed lines

            level = match.group("level")
            if level == "INFO":
                continue    # only collect warnings and errors

            category = match.group("category")
            errors_by_category[category].append({
                "timestamp": match.group("timestamp"),
                "level": level,
                "message": match.group("message"),
            })

    # Build summary using dict and list comprehensions
    summary = {
        category: {
            "count": len(events),
            "levels": list({e["level"] for e in events}),
            "latest": max(e["timestamp"] for e in events),
        }
        for category, events in errors_by_category.items()
    }

    return summary

